<template>
    <div id="box" v-if="state.title">
        <Header title="答题密码" v-if="!ifWx" />
        <div class="mainBox">
            <SubHeader :subTitle="state.title" v-if="state.title" />
            <van-form class="main" validate-first  >
                <van-field
                        v-model="state.pwd"
                        type="tel"
                        label=""
                        clearable
                        placeholder="请输入答题密码"
                        :rules="[

                    ]"
                />
                <div class="subBtnBox">
                    <van-button  block type="primary"  @click="onSubmit" >登录</van-button>
                </div>
            </van-form>
        </div>
        <Footer/>
    </div>
</template>

<script>
import Header from '@/components/Header'
import Footer from '@/components/Footer'
import SubHeader from '@/components/SubHeader'
import { reactive } from 'vue'
import { mapState } from 'vuex'
import useIfWx from '../../mixin/useIfWx'
export default {
    name: 'CheckQuestionPwd',
    components: {
        Header, Footer, SubHeader
    },
    setup() {
        const { ifWx } = useIfWx()
        const state = reactive({
            pwd: null,
            title: null
        })
        return {
            ifWx,
            state
        }
    },
    computed: {
        ...mapState({
            QuestionCellphone: state => state.QuestionCellphone
        })
    },
    async beforeRouteEnter(to, from, next) {
        next(vm => {
            vm.checkIfNeedPwd()
        })
    },
    mounted() {
    },
    methods: {
        // 提交验证问卷密码
        async onSubmit() {
            await this.Ajax('checkPwd', 'post', null, {
                mobile: this.QuestionCellphone,
                token: this.$route.query.token,
                password: this.state.pwd.replace(/(^\s*)|(\s*$)/ig, '')
            })
            this.pageNext()
        },
        // 检测是否需要答题密码
        async checkIfNeedPwd() {
            const res = await this.Ajax('checkIfNeedPwd', 'post', null, {
                mobile: this.QuestionCellphone,
                token: this.$route.query.token
            })
            if (!res.data.hasPassword) {
                this.pageNext()
                return
            }
            this.state.title = res.data.name
        },
        pageNext() {
            this.$router.push({
                name: 'questionnaire',
                query: this.route.query
            })
        }
    }
}
</script>

<style scoped lang="less">
    .van-cell{
        padding-left: 0;
        padding-right: 0;
        border-bottom: 1px solid #EAEEF2;
    }
    .subBtnBox{
        margin-top: 90px;
    }
</style>
